#include <stdio.h>
int main() {
    int n;
    scanf("%d", &n);
    int tet = 0, cube = 0, octa = 0, dode = 0, icosa = 0;
    for (int i = 0; i < n; i++) {
        char s[20];
        scanf("%s", s);
        if (strcmp(s, "Tetrahedron") == 0) tet++;
        else if (strcmp(s, "Cube") == 0) cube++;
        else if (strcmp(s, "Octahedron") == 0) octa++;
        else if (strcmp(s, "Dodecahedron") == 0) dode++;
        else if (strcmp(s, "Icosahedron") == 0) icosa++;
    }
    printf("%d %d %d %d %d\n", tet, cube, octa, dode, icosa);
    return 0;
}

