#include <iostream>
#include <string>
using namespace std;
int main() {
    int n;
    cin >> n;
    int tet = 0, cube = 0, octa = 0, dode = 0, icosa = 0;
    for (int i = 0; i < n; i++) {
        string s;
        cin >> s;
        if (s == "Tetrahedron") tet++;
        else if (s == "Cube") cube++;
        else if (s == "Octahedron") octa++;
        else if (s == "Dodecahedron") dode++;
        else if (s == "Icosahedron") icosa++;
    }
    cout << tet << " " << cube << " " << octa << " " << dode << " " << icosa << endl;
    return 0;
}

