import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        int tet = 0, cube = 0, octa = 0, dode = 0, icosa = 0;
        sc.nextLine();
        for (int i = 0; i < n; i++) {
            String s = sc.nextLine();
            if (s.equals("Tetrahedron")) tet++;
            else if (s.equals("Cube")) cube++;
            else if (s.equals("Octahedron")) octa++;
            else if (s.equals("Dodecahedron")) dode++;
            else if (s.equals("Icosahedron")) icosa++;
        }
        System.out.println(tet + " " + cube + " " + octa + " " + dode + " " + icosa);
    }
}

code.JavaScript:
const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let n;
let tet = 0, cube = 0, octa = 0, dode = 0, icosa = 0;
readline.on('line', line => {
    if (i == 0) {
        n = parseInt(line);
    } else {
        if (line == 'Tetrahedron') tet++;
        else if (line == 'Cube') cube++;
        else if (line == 'Octahedron') octa++;
        else if (line == 'Dodecahedron') dode++;
        else if (line == 'Icosahedron') icosa++;
        if (i == n) {
            console.log(tet + ' ' + cube + ' ' + octa + ' ' + dode + ' ' + icosa);
            readline.close();
        }
    }
    i++;
});

